/**
 * /app/styleguide — Design Token Reference
 *
 * Reads from tokens.json via the `tokens` raw export.
 * Displays every token with per-brand values.
 */

import { tokens, spacing } from '@/styles/design-tokens'

const BRANDS = ['OAL', 'MNN', 'TGR', 'LAL', 'IB'] as const
type Brand = typeof BRANDS[number]

// Shorthand helpers
const c = (tokens as any).colors
const r = (tokens as any).radius
const BRAND: Brand = 'TGR'

// TGR values used for UI chrome (borders, text, backgrounds of the styleguide itself)
const ui = {
  text:          c?.text?.primary?.[BRAND]      ?? '#1e1e1e',
  textSecondary: c?.text?.secondary?.[BRAND]    ?? '#808080',
  surface:       c?.surface?.primary?.[BRAND]   ?? '#f8f8f8',
  bg:            c?.brand?.secondary?.[BRAND]   ?? '#ffffff',
  accent:        c?.brand?.primary?.[BRAND]     ?? '#1e1e1e',
  accentText:    c?.brand?.secondary?.[BRAND]   ?? '#ffffff',
  border:        c?.input?.border?.[BRAND]      ?? '#ebebeb',
}

// ─── Section shell ────────────────────────────────────────────────────────────

function Section({ title, children }: { title: string; children: React.ReactNode }) {
  return (
    <section style={{ marginBottom: 64 }}>
      <h2
        style={{
          fontSize: 13,
          fontWeight: 700,
          letterSpacing: '0.08em',
          textTransform: 'uppercase',
          borderBottom: `1px solid ${ui.border}`,
          paddingBottom: 10,
          marginBottom: 24,
          color: ui.textSecondary,
          margin: '0 0 24px',
        }}
      >
        {title}
      </h2>
      {children}
    </section>
  )
}

// ─── Brand color row ──────────────────────────────────────────────────────────

function BrandRow({ label, getValue }: { label: string; getValue: (brand: Brand) => string | undefined }) {
  return (
    <div
      style={{
        display: 'grid',
        gridTemplateColumns: '200px repeat(5, 1fr)',
        alignItems: 'center',
        gap: 8,
        padding: '8px 0',
        borderBottom: `1px solid ${ui.border}`,
      }}
    >
      <code style={{ fontSize: 11, fontFamily: 'monospace', color: ui.text }}>{label}</code>
      {BRANDS.map((brand) => {
        const value = getValue(brand)
        if (!value) return <div key={brand} style={{ fontSize: 10, color: ui.textSecondary, textAlign: 'center' }}>—</div>
        const isDark = isColorDark(value)
        return (
          <div key={brand} style={{ textAlign: 'center' }}>
            <div
              title={value}
              style={{
                height: 28,
                borderRadius: 4,
                background: value,
                border: `1px solid ${ui.border}`,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                marginBottom: 3,
              }}
            >
              <span style={{ fontSize: 9, fontFamily: 'monospace', color: isDark ? '#fff' : '#000', opacity: 0.75 }}>
                {value}
              </span>
            </div>
            <span style={{ fontSize: 9, color: ui.textSecondary }}>{brand}</span>
          </div>
        )
      })}
    </div>
  )
}

// ─── Spacing row ──────────────────────────────────────────────────────────────

function SpacingRow({ name, value }: { name: string; value: number }) {
  return (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        gap: 16,
        padding: '8px 0',
        borderBottom: `1px solid ${ui.border}`,
      }}
    >
      <code style={{ width: 60, fontSize: 12, fontFamily: 'monospace', color: ui.accent, flexShrink: 0 }}>{name}</code>
      <span style={{ width: 44, fontSize: 12, color: ui.textSecondary, fontFamily: 'monospace', flexShrink: 0 }}>{value}px</span>
      <div style={{ height: 16, width: value, background: ui.accent, borderRadius: 2, opacity: 0.3, flexShrink: 0 }} />
    </div>
  )
}

// ─── Radius row ───────────────────────────────────────────────────────────────

function RadiusRow({ name, getValue }: { name: string; getValue: (brand: Brand) => number | undefined }) {
  return (
    <div
      style={{
        display: 'grid',
        gridTemplateColumns: '120px repeat(5, 1fr)',
        alignItems: 'center',
        gap: 8,
        padding: '8px 0',
        borderBottom: `1px solid ${ui.border}`,
      }}
    >
      <code style={{ fontSize: 11, fontFamily: 'monospace', color: ui.text }}>{name}</code>
      {BRANDS.map((brand) => {
        const value = getValue(brand)
        if (value === undefined) return <div key={brand} style={{ fontSize: 10, color: ui.textSecondary, textAlign: 'center' }}>—</div>
        const display = value >= 100 ? 'full' : `${value}px`
        return (
          <div key={brand} style={{ textAlign: 'center' }}>
            <div
              style={{
                width: 40,
                height: 40,
                background: ui.surface,
                border: `2px solid ${ui.border}`,
                borderRadius: Math.min(value, 20),
                margin: '0 auto 4px',
              }}
            />
            <span style={{ fontSize: 9, fontFamily: 'monospace', color: ui.textSecondary }}>{display}</span>
            <br />
            <span style={{ fontSize: 9, color: ui.textSecondary }}>{brand}</span>
          </div>
        )
      })}
    </div>
  )
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

function isColorDark(hex: string): boolean {
  const h = hex.replace('#', '')
  if (h.length < 6) return false
  const r = parseInt(h.substring(0, 2), 16)
  const g = parseInt(h.substring(2, 4), 16)
  const b = parseInt(h.substring(4, 6), 16)
  return (r * 299 + g * 587 + b * 114) / 1000 < 128
}

// ─── Page ────────────────────────────────────────────────────────────────────

export default function StyleGuidePage() {
  return (
    <div
      style={{
        fontFamily: "'Lato', system-ui, sans-serif",
        color: ui.text,
        background: ui.bg,
        minHeight: '100vh',
      }}
    >
      {/* Header */}
      <header
        style={{
          background: ui.accent,
          color: ui.accentText,
          padding: '28px 48px',
          marginBottom: 48,
        }}
      >
        <p style={{ margin: '0 0 4px', fontSize: 12, letterSpacing: '0.1em', textTransform: 'uppercase', opacity: 0.6 }}>
          AI Design System · All Brands
        </p>
        <h1 style={{ margin: 0, fontSize: 32, fontWeight: 700, letterSpacing: '-0.01em' }}>
          Style Guide
        </h1>
        <p style={{ margin: '8px 0 0', fontSize: 14, opacity: 0.7 }}>
          Source of truth: Figma → tokens.json — OAL · MNN · TGR · LAL · IB
        </p>
      </header>

      <div style={{ maxWidth: 1200, margin: '0 auto', padding: '0 48px 80px' }}>

        {/* ── Brand header row ── */}
        <div
          style={{
            display: 'grid',
            gridTemplateColumns: '200px repeat(5, 1fr)',
            gap: 8,
            marginBottom: 8,
            padding: '0 0 8px',
            borderBottom: `2px solid ${ui.border}`,
          }}
        >
          <div />
          {BRANDS.map((b) => (
            <div key={b} style={{ textAlign: 'center', fontSize: 11, fontWeight: 700, color: ui.textSecondary, letterSpacing: '0.06em' }}>
              {b}
            </div>
          ))}
        </div>

        {/* ── Colors: Background ── */}
        <Section title="Colors — Background">
          <BrandRow label="background" getValue={(b) => c?.background?.[b]} />
        </Section>

        {/* ── Colors: Text ── */}
        <Section title="Colors — Text">
          <BrandRow label="text / primary"   getValue={(b) => c?.text?.primary?.[b]} />
          <BrandRow label="text / secondary" getValue={(b) => c?.text?.secondary?.[b]} />
          <BrandRow label="text / disabled"  getValue={(b) => c?.text?.disabled?.[b]} />
        </Section>

        {/* ── Colors: Surface ── */}
        <Section title="Colors — Surface">
          <BrandRow label="surface / primary"   getValue={(b) => c?.surface?.primary?.[b]} />
          <BrandRow label="surface / secondary" getValue={(b) => c?.surface?.secondary?.[b]} />
          <BrandRow label="surface / disabled"  getValue={(b) => c?.surface?.disabled?.[b]} />
        </Section>

        {/* ── Colors: Brand ── */}
        <Section title="Colors — Brand">
          <BrandRow label="brand / primary"   getValue={(b) => c?.brand?.primary?.[b]} />
          <BrandRow label="brand / secondary" getValue={(b) => c?.brand?.secondary?.[b]} />
        </Section>

        {/* ── Colors: Feedback ── */}
        <Section title="Colors — Feedback">
          <BrandRow label="feedback / error"   getValue={(b) => c?.feedback?.error?.[b]} />
          <BrandRow label="feedback / warning" getValue={(b) => c?.feedback?.warning?.[b]} />
          <BrandRow label="feedback / success" getValue={(b) => c?.feedback?.success?.[b]} />
          <BrandRow label="feedback / info"    getValue={(b) => c?.feedback?.info?.[b]} />
        </Section>

        {/* ── Colors: Buttons ── */}
        <Section title="Colors — Buttons">
          {['primary', 'secondary', 'a2c', 'preview', 'disabled', 'danger', 'success', 'link'].map((variant) => (
            <div key={variant}>
              <p style={{ fontSize: 11, fontWeight: 600, color: ui.textSecondary, margin: '12px 0 4px', textTransform: 'uppercase', letterSpacing: '0.06em' }}>
                {variant}
              </p>
              <BrandRow label="button bg"   getValue={(b) => c?.button?.[variant]?.bg?.[b]} />
              <BrandRow label="button text" getValue={(b) => c?.button?.[variant]?.text?.[b]} />
              {variant !== 'link' && (
                <BrandRow label="button border" getValue={(b) => c?.button?.[variant]?.border?.[b]} />
              )}
            </div>
          ))}
        </Section>

        {/* ── Colors: Input ── */}
        <Section title="Colors — Input">
          <BrandRow label="input / bg"          getValue={(b) => c?.input?.bg?.[b]} />
          <BrandRow label="input / border"      getValue={(b) => c?.input?.border?.[b]} />
          <BrandRow label="input / text"        getValue={(b) => c?.input?.text?.[b]} />
          <BrandRow label="input / placeholder" getValue={(b) => c?.input?.placeholder?.[b]} />
        </Section>

        {/* ── Colors: Ribbon ── */}
        <Section title="Colors — Ribbon">
          {['default', 'bundle', 'oos', 'secondary'].map((variant) => (
            <div key={variant}>
              <p style={{ fontSize: 11, fontWeight: 600, color: ui.textSecondary, margin: '12px 0 4px', textTransform: 'uppercase', letterSpacing: '0.06em' }}>
                {variant}
              </p>
              <BrandRow label="ribbon bg"   getValue={(b) => c?.ribbon?.[variant]?.bg?.[b]} />
              <BrandRow label="ribbon text" getValue={(b) => c?.ribbon?.[variant]?.text?.[b]} />
            </div>
          ))}
        </Section>

        {/* ── Colors: Price ── */}
        <Section title="Colors — Price">
          <BrandRow label="price / selling"         getValue={(b) => c?.price?.selling?.[b]} />
          <BrandRow label="price / crossed"         getValue={(b) => c?.price?.crossed?.[b]} />
          <BrandRow label="price / discount text"   getValue={(b) => c?.price?.discount?.text?.[b]} />
          <BrandRow label="price / discount bg"     getValue={(b) => c?.price?.discount?.bg?.[b]} />
        </Section>

        {/* ── Colors: Card ── */}
        <Section title="Colors — Card">
          <BrandRow label="card / image bg" getValue={(b) => c?.card?.imageBg?.[b]} />
        </Section>

        {/* ── Border Radius ── */}
        <Section title="Border Radius">
          {r && Object.keys(r).map((name) => (
            <RadiusRow key={name} name={name} getValue={(b) => r[name]?.[b]} />
          ))}
        </Section>

        {/* ── Spacing ── */}
        <Section title="Spacing (shared across all brands)">
          <div style={{ maxWidth: 480 }}>
            {(Object.entries(spacing ?? {}) as [string, number][]).map(([name, value]) => (
              <SpacingRow key={name} name={name} value={value} />
            ))}
          </div>
        </Section>

      </div>
    </div>
  )
}
